import{_ as l,r,o as n,c,a as d,b as t,d as o,e as i}from"./app-7b6a7290.js";const s={},p={href:"https://github.com/garrytan/gstack",target:"_blank",rel:"noopener noreferrer"},h={href:"https://github.com/garrytan/gstack",target:"_blank",rel:"noopener noreferrer"},u={href:"https://github.com/garrytan/gstack",target:"_blank",rel:"noopener noreferrer"},g={href:"https://github.com/garrytan/gstack/blob/main/README.md",target:"_blank",rel:"noopener noreferrer"},k={href:"https://cloud.tencent.com/developer/article/2652471",target:"_blank",rel:"noopener noreferrer"},v={href:"https://www.mindstudio.ai/blog/what-is-gstack-gary-tan-claude-code-framework",target:"_blank",rel:"noopener noreferrer"},m={href:"https://zhuanlan.zhihu.com/p/2019068620324492892",target:"_blank",rel:"noopener noreferrer"};function b(f,e){const a=r("ExternalLinkIcon");return n(),c("div",null,[e[12]||(e[12]=d("h1",{id:"gstack-把-claude-code-组织成一支虚拟工程团队",tabindex:"-1"},[d("a",{class:"header-anchor",href:"#gstack-把-claude-code-组织成一支虚拟工程团队","aria-hidden":"true"},"#"),t(" GStack：把 Claude Code 组织成一支虚拟工程团队")],-1)),e[13]||(e[13]=d("h2",{id:"先校准-这里的-gstack-是什么",tabindex:"-1"},[d("a",{class:"header-anchor",href:"#先校准-这里的-gstack-是什么","aria-hidden":"true"},"#"),t(" 先校准：这里的 GStack 是什么")],-1)),e[14]||(e[14]=d("p",null,[t("这里说的 "),d("strong",null,"GStack"),t("，不是 Linux 里用来抓线程调用栈的 "),d("code",null,"gstack"),t("，也不是一个泛泛而谈的 “goal stack” 概念。")],-1)),d("p",null,[e[1]||(e[1]=t("这里的 GStack 指的是 ",-1)),d("a",p,[e[0]||(e[0]=t("garrytan/gstack",-1)),o(a)]),e[2]||(e[2]=t("：Garry Tan 开源的一套面向 Claude Code 的技能、斜杠命令和工作流约定。它的目标不是替换 Claude Code，而是把 Claude Code 从“会写代码的助手”组织成一支更像真实创业团队的虚拟团队：CEO、工程经理、设计师、代码 reviewer、QA lead、安全负责人、发布工程师等角色各自负责不同阶段。",-1))]),e[15]||(e[15]=i(`<p>所以，更准确地说：</p><ul><li>GStack 不是新模型，也不是新的 IDE。</li><li>GStack 不是 Anthropic 或 YC 的官方产品。</li><li>GStack 是一套 Markdown 驱动的角色提示词、技能和斜杠命令集合。</li><li>GStack 的核心价值是给 Claude Code 加上产品、工程、设计、质量、安全、发布和复盘流程。</li></ul><p>如果直接把 AI coding agent 当作“更快的自动补全”，很容易得到速度很快但方向混乱的产出。GStack 想解决的正是这个问题：让 agent 在动手写代码之前先思考目标，在合并之前接受审查，在上线之前经过 QA，在发布之后留下文档和复盘。</p><h2 id="它解决什么问题" tabindex="-1"><a class="header-anchor" href="#它解决什么问题" aria-hidden="true">#</a> 它解决什么问题</h2><p>Claude Code 本身已经能读写文件、运行命令、执行测试、修改代码、提交变更。问题在于：这些能力越强，如果没有流程约束，越容易把错误放大。</p><p>GStack 给 Claude Code 补上的不是“更聪明的大脑”，而是一套团队式协作结构：</p><ul><li>产品方向：先判断问题值不值得做。</li><li>工程计划：把想法变成可执行的架构和任务。</li><li>设计体验：检查用户路径、界面、交互和开发体验。</li><li>代码审查：发现实现风险、边界条件和安全问题。</li><li>QA 验证：在真实浏览器或真实环境里验收行为。</li><li>发布交付：把变更落地到部署、文档、监控和复盘。</li></ul><p>这也是为什么 GStack 更像一个“软件工厂”或“虚拟创业团队”，而不只是一个斜杠命令包。</p><h2 id="核心流程" tabindex="-1"><a class="header-anchor" href="#核心流程" aria-hidden="true">#</a> 核心流程</h2><p>GStack 的 README 和相关文章都强调类似的 sprint 流程：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Think -&gt; Plan -&gt; Build -&gt; Review -&gt; Test -&gt; Ship -&gt; Reflect
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>可以把它理解成一条完整的软件交付链路：</p><table><thead><tr><th>阶段</th><th>目标</th><th>常见 GStack 命令</th></tr></thead><tbody><tr><td>Think</td><td>澄清用户、痛点、机会和优先级</td><td><code>/office-hours</code>, <code>/plan-ceo-review</code></td></tr><tr><td>Plan</td><td>形成技术方案、任务拆分和风险清单</td><td><code>/plan-eng-review</code>, <code>/autoplan</code>, <code>/spec</code></td></tr><tr><td>Build</td><td>让 Claude Code 或其他 agent 实现代码</td><td>Claude Code 原生命令、<code>/investigate</code></td></tr><tr><td>Review</td><td>让 reviewer、安全、设计、DX 等角色审查</td><td><code>/review</code>, <code>/cso</code>, <code>/design-review</code>, <code>/devex-review</code></td></tr><tr><td>Test</td><td>用测试和浏览器 QA 验证真实行为</td><td><code>/qa</code>, <code>/qa-only</code>, <code>/browse</code></td></tr><tr><td>Ship</td><td>发布、部署、写 release 文档</td><td><code>/ship</code>, <code>/land-and-deploy</code>, <code>/canary</code>, <code>/document-release</code></td></tr><tr><td>Reflect</td><td>总结经验，沉淀到项目记忆</td><td><code>/retro</code>, <code>/learn</code></td></tr></tbody></table><p>这条链路的重点不是“每次都机械地跑完所有命令”，而是让你在不同风险阶段调用不同角色。小改动可以轻量走流程，大改动就应该让计划、审查、QA 和发布更完整。</p><h2 id="角色和命令地图" tabindex="-1"><a class="header-anchor" href="#角色和命令地图" aria-hidden="true">#</a> 角色和命令地图</h2>`,15)),d("p",null,[e[4]||(e[4]=t("GStack 的命令会随仓库演进，实际列表要以 ",-1)),d("a",h,[e[3]||(e[3]=t("官方 README",-1)),o(a)]),e[5]||(e[5]=t(" 为准。下面是按使用场景整理的理解方式。",-1))]),e[16]||(e[16]=i(`<table><thead><tr><th>场景</th><th>角色</th><th>常用命令</th><th>价值</th></tr></thead><tbody><tr><td>产品判断</td><td>YC office hours、CEO</td><td><code>/office-hours</code>, <code>/plan-ceo-review</code></td><td>判断问题是否真实、目标是否清晰、优先级是否合理</td></tr><tr><td>工程规划</td><td>工程经理、架构 reviewer</td><td><code>/plan-eng-review</code>, <code>/autoplan</code>, <code>/spec</code></td><td>检查方案、依赖、边界条件、测试策略和实施顺序</td></tr><tr><td>设计体验</td><td>产品设计、设计系统、前端体验</td><td><code>/plan-design-review</code>, <code>/design-consultation</code>, <code>/design-shotgun</code>, <code>/design-html</code></td><td>让界面、交互、文案和用户路径更完整</td></tr><tr><td>开发体验</td><td>DevEx reviewer</td><td><code>/plan-devex-review</code>, <code>/devex-review</code></td><td>检查 API、工具链、脚手架、文档和维护成本</td></tr><tr><td>调试研究</td><td>调查员</td><td><code>/investigate</code></td><td>在动手改代码前先收集证据、定位根因</td></tr><tr><td>代码审查</td><td>Senior reviewer</td><td><code>/review</code>, <code>/codex</code></td><td>发现 bug、回归风险、缺失测试和实现问题</td></tr><tr><td>安全审查</td><td>CSO、安全 reviewer</td><td><code>/cso</code></td><td>检查权限、注入、数据泄露和供应链风险</td></tr><tr><td>浏览器 QA</td><td>QA lead</td><td><code>/qa</code>, <code>/qa-only</code>, <code>/browse</code>, <code>/open-gstack-browser</code></td><td>通过真实页面和真实操作验证功能</td></tr><tr><td>发布上线</td><td>Release engineer、SRE</td><td><code>/ship</code>, <code>/land-and-deploy</code>, <code>/canary</code>, <code>/benchmark</code></td><td>管理发布、灰度、性能、回滚和上线记录</td></tr><tr><td>文档复盘</td><td>文档、复盘、记忆沉淀</td><td><code>/document-release</code>, <code>/document-generate</code>, <code>/retro</code>, <code>/learn</code></td><td>让项目知识随着代码一起更新</td></tr><tr><td>风险控制</td><td>状态保护、护栏</td><td><code>/careful</code>, <code>/freeze</code>, <code>/guard</code>, <code>/unfreeze</code></td><td>在高风险修改里降低误改、乱改和越界操作</td></tr></tbody></table><p>GStack 的强项不在于某一个命令多神奇，而在于这些角色能串起来。比如一个功能可以先经过 <code>/office-hours</code> 定义问题，再用 <code>/plan-eng-review</code> 修正计划，实现后跑 <code>/review</code>，最后用 <code>/qa</code> 和 <code>/ship</code> 收尾。</p><h2 id="安装方式" tabindex="-1"><a class="header-anchor" href="#安装方式" aria-hidden="true">#</a> 安装方式</h2><p>根据 GStack README，常规安装需要：</p><ul><li>Claude Code</li><li>Git</li><li>Bun v1+</li><li>Windows 环境下还需要 Node.js</li></ul><p>全局安装示例：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> clone --single-branch <span class="token parameter variable">--depth</span> <span class="token number">1</span> https://github.com/garrytan/gstack.git ~/.claude/skills/gstack
<span class="token builtin class-name">cd</span> ~/.claude/skills/gstack
./setup
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>./setup</code> 会把 GStack 接入 Claude Code，并在 <code>CLAUDE.md</code> 中加入相关配置段落。安装完成后，进入 Claude Code 就可以使用对应的斜杠命令。</p><p>如果是团队仓库，可以使用 team mode，把项目需要的 <code>.claude/</code> 和 <code>CLAUDE.md</code> 提交进仓库，让团队成员使用同一套 AI 协作约定：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">(</span>cd ~/.claude/skills/gstack <span class="token operator">&amp;&amp;</span> ./setup --team<span class="token punctuation">)</span> <span class="token operator">&amp;&amp;</span> ~/.claude/skills/gstack/bin/gstack-team-init required
<span class="token function">git</span> <span class="token function">add</span> .claude/ CLAUDE.md
<span class="token function">git</span> commit <span class="token parameter variable">-m</span> <span class="token string">&quot;require gstack for AI-assisted work&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>GStack 也逐渐支持 Claude Code 之外的 AI coding agent。README 中提到可以用 <code>./setup --host</code> 选择特定宿主，例如 Codex、Cursor、opencode 等。具体支持列表和安装参数仍应以仓库 README 为准。</p><h2 id="新手怎么开始" tabindex="-1"><a class="header-anchor" href="#新手怎么开始" aria-hidden="true">#</a> 新手怎么开始</h2><p>如果你第一次用 GStack，不建议一上来就把所有命令都跑一遍。更好的方式是从一条完整但轻量的链路开始。</p><ol><li>用 <code>/office-hours</code> 讲清楚你要解决的问题。</li><li>用 <code>/plan-ceo-review</code> 检查这个功能是否值得做、范围是否太大。</li><li>用 <code>/plan-eng-review</code> 或 <code>/autoplan</code> 把它变成可实施计划。</li><li>让 Claude Code 按计划实现代码。</li><li>用 <code>/review</code> 做代码审查。</li><li>用 <code>/qa</code> 在真实页面或 staging 环境里验收。</li><li>用 <code>/ship</code> 或 <code>/document-release</code> 做发布收尾。</li></ol><p>这个流程跑一两次后，你会更容易感受到哪些命令适合你的项目。不要为了“用全套 GStack”而增加无意义步骤；它应该帮你减少混乱，而不是制造仪式感。</p><h2 id="如何用好-gstack" tabindex="-1"><a class="header-anchor" href="#如何用好-gstack" aria-hidden="true">#</a> 如何用好 GStack</h2><h3 id="_1-先让它挑战问题-而不是直接写代码" tabindex="-1"><a class="header-anchor" href="#_1-先让它挑战问题-而不是直接写代码" aria-hidden="true">#</a> 1. 先让它挑战问题，而不是直接写代码</h3><p>AI coding 最大的浪费，往往不是代码写慢了，而是把错误的问题写得很快。</p><p><code>/office-hours</code> 和 <code>/plan-ceo-review</code> 的价值就在这里：它们会把“我要做一个功能”拉回到“用户是谁、痛点是什么、为什么现在要做、最小可行范围是什么”。如果你还没想清楚需求，先用这些产品角色，而不是直接让 Claude Code 改文件。</p><h3 id="_2-把计划当成可审查产物" tabindex="-1"><a class="header-anchor" href="#_2-把计划当成可审查产物" aria-hidden="true">#</a> 2. 把计划当成可审查产物</h3><p>复杂需求不要直接交给 agent 自由发挥。先要求它产出计划，再用 <code>/plan-eng-review</code> 或 <code>/autoplan</code> 审查计划。</p><p>一个好的 GStack 计划至少应该回答：</p><ul><li>需要改哪些模块。</li><li>会影响哪些现有行为。</li><li>关键边界条件是什么。</li><li>应该补哪些测试。</li><li>哪些步骤可以并行，哪些必须串行。</li><li>如果失败，如何回滚或缩小范围。</li></ul><p>计划阶段越清楚，后面的代码审查和 QA 越有效。</p><h3 id="_3-把-review-当作默认门槛" tabindex="-1"><a class="header-anchor" href="#_3-把-review-当作默认门槛" aria-hidden="true">#</a> 3. 把 <code>/review</code> 当作默认门槛</h3><p>GStack 的 <code>/review</code> 不应该只在“大版本”里使用。只要变更会影响用户行为、数据、权限、支付、发布流程或共享模块，都值得跑一次 review。</p><p>你可以明确要求 reviewer 关注：</p><ul><li>行为回归</li><li>错误处理</li><li>数据兼容性</li><li>权限边界</li><li>并发和状态一致性</li><li>缺失测试</li><li>可维护性</li></ul><p>这比简单问“代码有没有问题”更有效。</p><h3 id="_4-用真实环境做-qa" tabindex="-1"><a class="header-anchor" href="#_4-用真实环境做-qa" aria-hidden="true">#</a> 4. 用真实环境做 QA</h3><p><code>/qa</code> 的价值不是“再读一遍代码”，而是让 agent 像 QA lead 一样操作真实界面、真实 URL 或 staging 环境。</p><p>好的 QA 请求应该包含：</p><ul><li>要验收的 URL 或页面入口。</li><li>用户应该完成的关键路径。</li><li>需要覆盖的异常路径。</li><li>哪些状态必须截图或记录。</li><li>发现问题后是否允许直接修复。</li></ul><p>对于前端、支付、登录、权限、发布配置等场景，浏览器 QA 往往比静态分析更接近真实风险。</p><h3 id="_5-把安全和发布单独拉出来" tabindex="-1"><a class="header-anchor" href="#_5-把安全和发布单独拉出来" aria-hidden="true">#</a> 5. 把安全和发布单独拉出来</h3><p>当功能涉及 token、密钥、用户数据、权限、第三方 API、部署脚本时，不要只依赖普通 review。可以加入 <code>/cso</code>、<code>/guard</code>、<code>/freeze</code> 等命令，让安全和状态保护成为显式步骤。</p><p>发布前则可以使用 <code>/ship</code>、<code>/canary</code>、<code>/benchmark</code>、<code>/document-release</code> 等命令，把上线检查、性能、文档和回滚思路一起纳入交付过程。</p><h3 id="_6-不要让并行-agent-变成并行混乱" tabindex="-1"><a class="header-anchor" href="#_6-不要让并行-agent-变成并行混乱" aria-hidden="true">#</a> 6. 不要让并行 agent 变成并行混乱</h3><p>GStack 很强调“并行 sprint”能力，但并行的前提是任务边界清楚。多个 agent 同时工作时，最重要的不是数量，而是：</p><ul><li>每个 agent 的目标是否独立。</li><li>是否有统一计划和验收标准。</li><li>是否避免修改同一批文件。</li><li>是否有最终 review 汇总。</li><li>是否有测试和 QA 作为统一收口。</li></ul><p>没有流程的并行，只会把冲突、重复劳动和难以审查的变更放大。</p><h3 id="_7-团队项目优先用-team-mode" tabindex="-1"><a class="header-anchor" href="#_7-团队项目优先用-team-mode" aria-hidden="true">#</a> 7. 团队项目优先用 team mode</h3><p>如果只是个人实验，全局安装就够了。团队项目更推荐把 GStack 约定落到仓库里，例如 <code>.claude/</code> 和 <code>CLAUDE.md</code>。</p><p>这样做的好处是：</p><ul><li>每个人使用同一套 AI 协作规范。</li><li>reviewer、QA、发布流程不依赖某个成员的本地习惯。</li><li>项目记忆、约束和命令入口更容易维护。</li><li>新成员进入项目时更容易复用已有流程。</li></ul><h3 id="_8-把输出当证据-不要当权威" tabindex="-1"><a class="header-anchor" href="#_8-把输出当证据-不要当权威" aria-hidden="true">#</a> 8. 把输出当证据，不要当权威</h3><p>GStack 会让 Claude Code 的角色分工更像团队，但它不会让 AI 自动变成事实来源。任何 review、QA、发布建议都应该回到证据：</p><ul><li>测试是否真的跑过。</li><li>页面是否真的打开过。</li><li>日志是否真的看过。</li><li>失败是否真的复现过。</li><li>修复是否真的覆盖了回归用例。</li></ul><p>GStack 的正确用法是提高工程纪律，而不是替代工程判断。</p><h2 id="适合谁" tabindex="-1"><a class="header-anchor" href="#适合谁" aria-hidden="true">#</a> 适合谁</h2><p>GStack 比较适合这些人：</p><ul><li>独立开发者或 founder：想用 Claude Code 覆盖产品、工程、QA、发布等多个角色。</li><li>第一次使用 Claude Code 的人：需要一套现成工作流，而不想从空白提示词开始。</li><li>技术负责人或 staff engineer：想把 AI coding 引入团队流程，而不是让每个人各自随意使用。</li><li>小团队：希望用轻量方式建立 AI 协作规范、审查规范和发布规范。</li></ul><p>不太适合这些情况：</p><ul><li>只是一次性小改动，跑完整流程成本过高。</li><li>项目没有测试、没有可运行环境，也不打算补。</li><li>团队不愿意维护 <code>CLAUDE.md</code>、技能和项目约束。</li><li>你只想要无脑生成代码，而不想做 review、QA 和发布检查。</li></ul><h2 id="和普通-claude-md-的区别" tabindex="-1"><a class="header-anchor" href="#和普通-claude-md-的区别" aria-hidden="true">#</a> 和普通 CLAUDE.md 的区别</h2><p>普通 <code>CLAUDE.md</code> 通常是项目上下文：代码结构、运行命令、测试方式、约定、注意事项。</p><p>GStack 更像是在 <code>CLAUDE.md</code> 之上加入一套组织结构：</p><ul><li>不同角色该如何思考。</li><li>不同阶段该如何交接。</li><li>什么情况下需要 review、QA、安全或发布检查。</li><li>如何把工作从需求、计划、实现、验证一路推进到上线。</li></ul><p>换句话说，普通 <code>CLAUDE.md</code> 告诉 Claude Code “这个项目是什么”，GStack 进一步告诉它“在这个项目里应该怎么像团队一样工作”。</p><h2 id="使用时的注意事项" tabindex="-1"><a class="header-anchor" href="#使用时的注意事项" aria-hidden="true">#</a> 使用时的注意事项</h2><ol><li><strong>以 README 为准</strong>：GStack 仓库更新很快，命令数量和参数可能变化。</li><li><strong>控制成本</strong>：多角色、多轮 review 和 QA 会增加 token、时间和上下文成本。</li><li><strong>按风险选流程</strong>：不是所有改动都需要完整 sprint；越接近用户、数据、安全、发布，流程越应该完整。</li><li><strong>保留本地判断</strong>：GStack 是流程层，不是正确性的保证。</li><li><strong>可以 fork 和裁剪</strong>：如果团队只需要其中一部分角色，可以保留最有价值的命令，把不适合的流程删掉或改写。</li></ol><h2 id="一句话总结" tabindex="-1"><a class="header-anchor" href="#一句话总结" aria-hidden="true">#</a> 一句话总结</h2><p>GStack 的本质不是让 Claude Code “多几个命令”，而是给 Claude Code 加上一套创业团队式的软件交付流程：先判断问题，再做计划，再写代码，再 review，再 QA，再发布，再复盘。</p><p>用得好，它能把 AI coding 从“快但散”变成“快且有纪律”。</p><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2>`,65)),d("ul",null,[d("li",null,[d("a",u,[e[6]||(e[6]=t("garrytan/gstack GitHub 仓库",-1)),o(a)])]),d("li",null,[d("a",g,[e[7]||(e[7]=t("GStack README",-1)),o(a)])]),d("li",null,[d("a",k,[e[8]||(e[8]=t("腾讯云开发者文章：GStack：Garry Tan 开源 AI 编程框架",-1)),o(a)])]),d("li",null,[d("a",v,[e[9]||(e[9]=t("MindStudio：What is GStack? Gary Tan’s Claude Code framework explained",-1)),o(a)])]),d("li",null,[d("a",m,[e[10]||(e[10]=t("知乎文章：用户提供的补充阅读链接",-1)),o(a)]),e[11]||(e[11]=t("（当前环境无法抓取正文，本文未把它作为主要事实来源）",-1))])])])}const w=l(s,[["render",b],["__file","05Gstack.html.vue"]]);export{w as default};
